import{c as e,W as a,j as t,m as i}from"./chunks/framework.CoQR5MuA.js";const l=JSON.parse('{"title":"矿产开发部","description":"赞比亚国情资料 — 矿产开发部","frontmatter":{"title":"矿产开发部","description":"赞比亚国情资料 — 矿产开发部"},"headers":[],"relativePath":"mining/zambia/zh/mining-dept.md","filePath":"mining/zambia/zh/mining-dept.md","lastUpdated":1780319999000}'),n={name:"mining/zambia/zh/mining-dept.md"};function r(s,p,d,o,m,_){return a(),t("div",null,[...p[0]||(p[0]=[i('<h1 id="矿产开发部" tabindex="-1">矿产开发部 <a class="header-anchor" href="#矿产开发部" aria-label="Permalink to &quot;矿产开发部&quot;">​</a></h1><div class="reading-prose"><p>矿产开发部（MDD）的职责是促进矿产资源开发，确保所有采矿活动均按照《矿产和矿产开发法》及其附属立法的规定进行，确保矿产资源开发政策的实施。</p><p>MDD 的职能包括颁发和管理非采矿权（矿产贸易许可证、矿产进出口许可证和淘金证书），监督采矿和矿物加工作业，以确保其发展符合批准的运营计划并符合 2015 年《矿山和矿产开发法》第 11 条的规定。该部门还负责收集、汇编和传播矿产生产统计数据，并进行矿坑调查、设立信标和颁发挂钩证书，以及划定和调查采矿权。</p><p>技术部门结构</p><p>矿产开发部由以下部门组成：–</p><p>矿山开发</p><p>运营</p><p>矿产经济学</p><p>矿产开发科</p><p>矿山开发科（小型矿业开发）专注于小型采矿和矿物加工业务的发展。本科分为以下两个 (2) 个单元：</p><p>勘察单位</p><p>该部门负责：</p><p>采矿权区域划定与调查；</p><p>安装灯塔并颁发锚定证书；</p><p>矿坑勘测；以及</p><p>维护和更新所有采矿权区域的调查记录。</p><p>地区矿业局单位</p><p>该部门负责为小规模采矿者和矿物加工者提供现场技术服务。该部门共有六 (6) 个区域采矿局 (RMB)。区域采矿局位于以下城镇；</p><p>索尔韦齐 (西北省)</p><p>基特韦 (铜带省)</p><p>曼萨（卢阿普拉/北方省）</p><p>姆库希 (中央省)</p><p>奇帕塔 (东部/穆钦加省)</p><p>乔玛（南部/西部省）</p><p>行动组</p><p>运营部门（大型采矿业务）专注于评估拟议的大型采矿企业并监控大型运营以确保合规。本部门分为以下两个 (2) 个单元：</p><p>行动组</p><p>该部门负责监督和检查大型采矿作业，以确保遵守批准的采矿和矿物加工计划，并确保无浪费的采矿实践。</p><p>项目评估组</p><p>该部门负责通过可行性研究报告评估采矿项目，以确定其可行性并确保其按照已批准的运营计划进行开发。该部门还负责评估和监督采矿和矿物加工项目，以确保项目进入生产阶段。</p><p>矿产经济科</p><p>矿产经济部门专注于非采矿权的颁发和管理、矿产统计数据的收集、编制和处理，以及价值链各个环节的矿产生产的监测和核查。本部门分为两 (2) 个单元；</p><p>矿产经济部门</p><p>矿产经济部门负责：</p><p>收集、汇编和处理采矿统计数据（矿产生产、矿产出口和销售、金属/矿产价格、采矿投资和劳动力统计数据），以监测绩效并向最终用户提供数据；</p><p>办理矿产进出口许可证、矿产贸易许可证、淘金证。</p><p>矿产价值链部门</p><p>该单位负责监控矿物从矿场开采点到地磅运输，以及最终在边境口岸和机场出口的全过程。</p></div>',2)])])}const h=e(n,[["render",r]]);export{l as __pageData,h as default};
